class Solution {
    public int numberOfSpecialChars(String word) {
        int res = 0;
        for (char c = 'a'; c <= 'z'; c++) {
            int lower = -1, upper = -1;
            for (int i = 0; i < word.length(); i++) {
                if (word.charAt(i) == c) lower = i;
                if (word.charAt(i) == (char)(c - 'a' + 'A')) upper = i;
                if (upper != -1 && lower != -1 && lower > upper) break;
            }
            if (upper != -1 && lower != -1 && lower < upper) res++;
        }
        return res;
    }
}
